/// Tool use block in a response.
@immutable
class ToolUseBlock extends ContentBlock {
  /// Unique identifier for this tool use.
  final String id;

  /// Name of the tool being used.
  final String name;

  /// Input parameters for the tool.
  final Map<String, dynamic> input;

  /// Caller metadata for this tool invocation.
  final ToolCaller? caller;

  /// Creates a [ToolUseBlock].
  const ToolUseBlock({
    required this.id,
    required this.name,
    required this.input,
    this.caller,
  });

  /// Creates a [ToolUseBlock] from JSON.
  factory ToolUseBlock.fromJson(Map<String, dynamic> json) {
    return ToolUseBlock(
      id: json['id'] as String,
      name: json['name'] as String,
      input: json['input'] as Map<String, dynamic>,
      caller: json['caller'] != null
          ? ToolCaller.fromJson(json['caller'] as Map<String, dynamic>)
          : null,
    );
  }

  @override
  Map<String, dynamic> toJson() => {
    'type': 'tool_use',
    'id': id,
    'name': name,
    'input': input,
    if (caller != null) 'caller': caller!.toJson(),
  };

  /// Creates a copy with replaced values.
  ToolUseBlock copyWith({
    String? id,
    String? name,
    Map<String, dynamic>? input,
    Object? caller = unsetCopyWithValue,
  }) {
    return ToolUseBlock(
      id: id ?? this.id,
      name: name ?? this.name,
      input: input ?? this.input,
      caller: caller == unsetCopyWithValue
          ? this.caller
          : caller as ToolCaller?,
    );
  }

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is ToolUseBlock &&
          runtimeType == other.runtimeType &&
          id == other.id &&
          name == other.name &&
          mapsEqual(input, other.input) &&
          caller == other.caller;

  @override
  int get hashCode => Object.hash(id, name, mapHash(input), caller);

  @override
  String toString() =>
      'ToolUseBlock(id: $id, name: $name, input: $input, caller: $caller)';
